
UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=PV8CMZLKTpI', conteudo_texto = '<h2>Circuitos Elétricos</h2><p>Análise de circuitos em corrente contínua (CC) e corrente alternada (CA).</p><h3>⚡ Grandezas Fundamentais</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Grandeza</th><th style=''padding:10px;border:1px solid #ddd;''>Símbolo</th><th style=''padding:10px;border:1px solid #ddd;''>Unidade</th><th style=''padding:10px;border:1px solid #ddd;''>Fórmula</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Tensão</strong></td><td style=''padding:10px;border:1px solid #ddd;''>V ou U</td><td style=''padding:10px;border:1px solid #ddd;''>Volt (V)</td><td style=''padding:10px;border:1px solid #ddd;''>V = R × I</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Corrente</strong></td><td style=''padding:10px;border:1px solid #ddd;''>I</td><td style=''padding:10px;border:1px solid #ddd;''>Ampère (A)</td><td style=''padding:10px;border:1px solid #ddd;''>I = V / R</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Resistência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>R</td><td style=''padding:10px;border:1px solid #ddd;''>Ohm (Ω)</td><td style=''padding:10px;border:1px solid #ddd;''>R = V / I</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Potência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>P</td><td style=''padding:10px;border:1px solid #ddd;''>Watt (W)</td><td style=''padding:10px;border:1px solid #ddd;''>P = V × I</td></tr></table></div><h3>🔌 Lei de Ohm</h3><div style=''background:#d4edda;padding:20px;border-radius:8px;margin:15px 0;text-align:center;''><h3 style=''color:#28a745;''>V = R × I</h3><p>Tensão = Resistência × Corrente</p></div><h3>🔗 Associação de Resistores</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:250px;background:#e8f4f8;padding:15px;border-radius:8px;''><h4>Série</h4><ul><li>Mesma corrente em todos</li><li><strong>Req = R1 + R2 + R3...</strong></li><li>Tensão se divide</li></ul></div><div style=''flex:1;min-width:250px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>Paralelo</h4><ul><li>Mesma tensão em todos</li><li><strong>1/Req = 1/R1 + 1/R2...</strong></li><li>Corrente se divide</li></ul></div></div><h3>📐 Leis de Kirchhoff</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Lei</th><th style=''padding:10px;border:1px solid #ddd;''>Enunciado</th><th style=''padding:10px;border:1px solid #ddd;''>Aplicação</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>LKC (Nós)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>ΣI = 0 (soma das correntes em um nó é zero)</td><td style=''padding:10px;border:1px solid #ddd;''>Correntes entrando = saindo</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>LKT (Malhas)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>ΣV = 0 (soma das tensões em malha fechada é zero)</td><td style=''padding:10px;border:1px solid #ddd;''>Quedas = elevações de tensão</td></tr></table></div><h3>🌊 Corrente Alternada (CA)</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Conceito</th><th style=''padding:10px;border:1px solid #ddd;''>Definição</th><th style=''padding:10px;border:1px solid #ddd;''>Brasil</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Frequência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Ciclos por segundo (Hz)</td><td style=''padding:10px;border:1px solid #ddd;''>60 Hz</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Valor Eficaz (RMS)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Vef = Vp / √2</td><td style=''padding:10px;border:1px solid #ddd;''>127V ou 220V</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Impedância</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Z = √(R² + X²)</td><td style=''padding:10px;border:1px solid #ddd;''>Resistência em CA</td></tr></table></div><h3>📊 Potência em CA</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:150px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>P (Ativa)</strong><p>W - Trabalho real</p><p>P = V.I.cosφ</p></div><div style=''flex:1;min-width:150px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>Q (Reativa)</strong><p>VAr - Energia armazenada</p><p>Q = V.I.senφ</p></div><div style=''flex:1;min-width:150px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>S (Aparente)</strong><p>VA - Total</p><p>S = V.I</p></div></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>O <strong>fator de potência (FP = cosφ)</strong> é muito cobrado. FP = 1 é ideal. Quanto menor, mais energia reativa e desperdício!</p></div>' WHERE titulo = 'Resumo: Circuitos Elétricos';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=VnP3GQyx1AQ', conteudo_texto = '<h2>Máquinas Elétricas</h2><p>Transformadores, motores e geradores - conversão de energia elétrica.</p><h3>🔄 Classificação</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>⚡ Estáticas</strong><p>Transformadores</p><p>Não têm partes móveis</p></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>🔄 Rotativas</strong><p>Motores e Geradores</p><p>Conversão eletromecânica</p></div></div><h3>🔌 Transformadores</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p>Transfere energia entre circuitos por indução eletromagnética.</p><table style=''width:100%;border-collapse:collapse;margin-top:10px;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Relação</th><th style=''padding:10px;border:1px solid #ddd;''>Fórmula</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Tensão</strong></td><td style=''padding:10px;border:1px solid #ddd;''>V1/V2 = N1/N2</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Corrente</strong></td><td style=''padding:10px;border:1px solid #ddd;''>I1/I2 = N2/N1</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Potência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>S1 ≈ S2 (ideal)</td></tr></table><p style=''margin-top:10px;''><strong>Elevador:</strong> N2 > N1 | <strong>Abaixador:</strong> N2 < N1</p></div><h3>⚙️ Motores de Indução</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><p><strong>Mais usado na indústria!</strong> Robusto, barato e confiável.</p><table style=''width:100%;border-collapse:collapse;margin-top:10px;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Rotor</th><th style=''padding:10px;border:1px solid #ddd;''>Aplicação</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Gaiola de Esquilo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Barras curto-circuitadas</td><td style=''padding:10px;border:1px solid #ddd;''>Bombas, ventiladores, compressores</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Rotor Bobinado</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Enrolamentos com anéis</td><td style=''padding:10px;border:1px solid #ddd;''>Partida pesada, controle de velocidade</td></tr></table></div><h4>🔢 Conceitos Importantes</h4><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><ul><li><strong>Velocidade Síncrona:</strong> ns = 120f / p (f=frequência, p=polos)</li><li><strong>Escorregamento:</strong> s = (ns - n) / ns (diferença de velocidade)</li><li><strong>Motor 4 polos, 60Hz:</strong> ns = 1800 rpm</li></ul></div><h3>🔋 Motores Síncronos</h3><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;''><ul><li>Velocidade constante = velocidade síncrona</li><li>Rotor alimentado por CC (excitação)</li><li>Pode corrigir fator de potência</li><li>Usado em grandes cargas constantes</li></ul></div><h3>⚡ Geradores</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>Síncrono (Alternador)</h4><ul><li>Gera CA</li><li>Usinas hidrelétricas</li><li>Termelétricas</li></ul></div><div style=''flex:1;min-width:200px;background:#e8f4f8;padding:15px;border-radius:8px;''><h4>CC (Dínamo)</h4><ul><li>Gera CC</li><li>Aplicações específicas</li><li>Soldagem, galvanoplastia</li></ul></div></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Motor de indução <strong>nunca atinge</strong> a velocidade síncrona (senão não haveria indução). O <strong>escorregamento típico é 2-5%</strong>!</p></div>' WHERE titulo = 'Resumo: Máquinas Elétricas';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=5bPH9Lr6pY8', conteudo_texto = '<h2>Sistemas de Potência</h2><p>Geração, transmissão e distribuição de energia elétrica.</p><h3>⚡ Estrutura do Sistema Elétrico</h3><div style=''display:flex;gap:10px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:120px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>1️⃣ Geração</strong><p>Usinas</p></div><div style=''flex:1;min-width:120px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>2️⃣ Transmissão</strong><p>Alta tensão</p></div><div style=''flex:1;min-width:120px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>3️⃣ Distribuição</strong><p>Média/Baixa tensão</p></div><div style=''flex:1;min-width:120px;background:#e8f4f8;padding:15px;border-radius:8px;text-align:center;''><strong>4️⃣ Consumo</strong><p>Residências/Indústrias</p></div></div><h3>🏭 Geração de Energia</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Fonte</th><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>% Brasil</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Hidrelétrica</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Renovável</td><td style=''padding:10px;border:1px solid #ddd;''>~60%</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Eólica</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Renovável</td><td style=''padding:10px;border:1px solid #ddd;''>~12%</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Térmica (Gás)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Não renovável</td><td style=''padding:10px;border:1px solid #ddd;''>~8%</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Solar</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Renovável</td><td style=''padding:10px;border:1px solid #ddd;''>~4%</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Nuclear</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Não renovável</td><td style=''padding:10px;border:1px solid #ddd;''>~2%</td></tr></table></div><h3>🔌 Níveis de Tensão</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Nível</th><th style=''padding:10px;border:1px solid #ddd;''>Tensão</th><th style=''padding:10px;border:1px solid #ddd;''>Aplicação</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Extra Alta</strong></td><td style=''padding:10px;border:1px solid #ddd;''>> 230 kV</td><td style=''padding:10px;border:1px solid #ddd;''>Transmissão longas distâncias</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Alta</strong></td><td style=''padding:10px;border:1px solid #ddd;''>69-230 kV</td><td style=''padding:10px;border:1px solid #ddd;''>Transmissão/Subtransmissão</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Média</strong></td><td style=''padding:10px;border:1px solid #ddd;''>1-69 kV</td><td style=''padding:10px;border:1px solid #ddd;''>Distribuição primária</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Baixa</strong></td><td style=''padding:10px;border:1px solid #ddd;''>< 1 kV</td><td style=''padding:10px;border:1px solid #ddd;''>Consumidor final (127/220V)</td></tr></table></div><h3>🛡️ Proteção do Sistema</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>Equipamento</th><th style=''padding:10px;border:1px solid #ddd;''>Função</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Disjuntor</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Interrompe correntes de falta</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Relé de Proteção</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Detecta anormalidades e comanda disjuntor</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Para-raios</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Protege contra sobretensões atmosféricas</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>TC/TP</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Transformadores de medição</td></tr></table></div><h3>📊 Sistema Interligado Nacional (SIN)</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #28a745;''><ul><li>Interliga 4 subsistemas: Sul, Sudeste/CO, Nordeste, Norte</li><li>Operado pelo <strong>ONS</strong> (Operador Nacional do Sistema)</li><li>Permite transferência de energia entre regiões</li><li>Maior sistema interligado do mundo</li></ul></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Por que transmitir em <strong>alta tensão</strong>? Para reduzir perdas! P = I²R, aumentando V, reduzimos I e as perdas por efeito Joule!</p></div>' WHERE titulo = 'Resumo: Sistemas de Potência';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=u9aP5xjOXhY', conteudo_texto = '<h2>Eletrônica de Potência</h2><p>Conversores e controladores para processamento de energia elétrica.</p><h3>⚡ O que é Eletrônica de Potência?</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p>Área que utiliza <strong>dispositivos semicondutores</strong> para converter e controlar energia elétrica de forma eficiente.</p><p><strong>Aplicações:</strong> Inversores de frequência, fontes chaveadas, carregadores, drives de motores, energia solar.</p></div><h3>🔌 Dispositivos Semicondutores</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Dispositivo</th><th style=''padding:10px;border:1px solid #ddd;''>Característica</th><th style=''padding:10px;border:1px solid #ddd;''>Aplicação</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Diodo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Conduz em um sentido</td><td style=''padding:10px;border:1px solid #ddd;''>Retificadores</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Tiristor (SCR)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Semicontrolado</td><td style=''padding:10px;border:1px solid #ddd;''>Retificadores controlados</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>MOSFET</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Alta frequência</td><td style=''padding:10px;border:1px solid #ddd;''>Fontes chaveadas</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>IGBT</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Alta potência + frequência</td><td style=''padding:10px;border:1px solid #ddd;''>Inversores industriais</td></tr></table></div><h3>🔄 Tipos de Conversores</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>Conversor</th><th style=''padding:10px;border:1px solid #ddd;''>Entrada → Saída</th><th style=''padding:10px;border:1px solid #ddd;''>Aplicação</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Retificador</strong></td><td style=''padding:10px;border:1px solid #ddd;''>CA → CC</td><td style=''padding:10px;border:1px solid #ddd;''>Fontes de alimentação</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Inversor</strong></td><td style=''padding:10px;border:1px solid #ddd;''>CC → CA</td><td style=''padding:10px;border:1px solid #ddd;''>Drives, energia solar</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Chopper (CC-CC)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>CC → CC</td><td style=''padding:10px;border:1px solid #ddd;''>Reguladores de tensão</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Cicloconversor</strong></td><td style=''padding:10px;border:1px solid #ddd;''>CA → CA</td><td style=''padding:10px;border:1px solid #ddd;''>Controle de velocidade</td></tr></table></div><h3>🎛️ Controle PWM</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;''><h4>Modulação por Largura de Pulso</h4><p>Técnica de controle que varia o <strong>duty cycle</strong> (tempo ligado vs desligado) para controlar a potência média.</p><ul><li><strong>Duty Cycle 50%:</strong> Metade do tempo ligado</li><li><strong>Duty Cycle 100%:</strong> Sempre ligado</li><li>Usado em inversores, fontes chaveadas, controle de motores</li></ul></div><h3>⚙️ Inversores de Frequência</h3><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;''><p>Controlam a <strong>velocidade de motores de indução</strong> variando frequência e tensão.</p><h4>Estrutura:</h4><ol><li><strong>Retificador:</strong> CA da rede → CC</li><li><strong>Link CC:</strong> Filtragem e armazenamento</li><li><strong>Inversor:</strong> CC → CA com frequência variável</li></ol><p style=''margin-top:10px;''><strong>Benefícios:</strong> Economia de energia, partida suave, controle preciso de velocidade.</p></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>O <strong>IGBT</strong> é o dispositivo mais usado em inversores industriais por combinar alta potência do BJT com facilidade de acionamento do MOSFET!</p></div>' WHERE titulo = 'Resumo: Eletrônica de Potência';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=xK_2GL7xwNU', conteudo_texto = '<h2>Instrumentação</h2><p>Sensores, medição e controle de processos industriais.</p><h3>📊 O que é Instrumentação?</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p>Área que envolve <strong>medição, indicação, registro e controle</strong> de variáveis de processo como temperatura, pressão, vazão e nível.</p></div><h3>🌡️ Variáveis de Processo</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Variável</th><th style=''padding:10px;border:1px solid #ddd;''>Sensores Comuns</th><th style=''padding:10px;border:1px solid #ddd;''>Unidades</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Temperatura</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Termopar, PT100, Termistor</td><td style=''padding:10px;border:1px solid #ddd;''>°C, K, °F</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Pressão</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Bourdon, Strain gauge, Capacitivo</td><td style=''padding:10px;border:1px solid #ddd;''>Pa, bar, psi, kgf/cm²</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Vazão</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Placa de orifício, Coriolis, Ultrassônico</td><td style=''padding:10px;border:1px solid #ddd;''>m³/h, L/min, gpm</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Nível</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Boia, Radar, Ultrassônico, Pressão diferencial</td><td style=''padding:10px;border:1px solid #ddd;''>m, %, mm</td></tr></table></div><h3>🌡️ Sensores de Temperatura</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>Termopar</h4><ul><li>Dois metais diferentes</li><li>Ampla faixa (-200 a +1800°C)</li><li>Tipos: J, K, T, E, S, R</li></ul></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>RTD (PT100)</h4><ul><li>Resistência varia com T</li><li>Alta precisão</li><li>Faixa: -200 a +850°C</li></ul></div></div><h3>🔄 Malha de Controle</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><div style=''display:flex;gap:10px;flex-wrap:wrap;justify-content:center;align-items:center;''><span style=''background:#0066cc;color:white;padding:10px 15px;border-radius:8px;''>Setpoint</span><span>→</span><span style=''background:#28a745;color:white;padding:10px 15px;border-radius:8px;''>Controlador</span><span>→</span><span style=''background:#ffc107;color:black;padding:10px 15px;border-radius:8px;''>Elemento Final</span><span>→</span><span style=''background:#dc3545;color:white;padding:10px 15px;border-radius:8px;''>Processo</span><span>→</span><span style=''background:#6f42c1;color:white;padding:10px 15px;border-radius:8px;''>Sensor</span><span>↩️</span></div><p style=''text-align:center;margin-top:10px;''><em>Malha fechada com realimentação</em></p></div><h3>🎛️ Controlador PID</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Ação</th><th style=''padding:10px;border:1px solid #ddd;''>Função</th><th style=''padding:10px;border:1px solid #ddd;''>Efeito</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>P (Proporcional)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Corrige proporcional ao erro</td><td style=''padding:10px;border:1px solid #ddd;''>Resposta rápida, deixa erro residual</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>I (Integral)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Elimina erro acumulado</td><td style=''padding:10px;border:1px solid #ddd;''>Zera erro, pode oscilar</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>D (Derivativo)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Antecipa mudanças</td><td style=''padding:10px;border:1px solid #ddd;''>Reduz overshoot, sensível a ruído</td></tr></table></div><h3>📡 Sinais de Transmissão</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:150px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>4-20 mA</strong><p>Analógico padrão</p></div><div style=''flex:1;min-width:150px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>0-10 V</strong><p>Tensão analógica</p></div><div style=''flex:1;min-width:150px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>HART</strong><p>Híbrido (4-20 + digital)</p></div><div style=''flex:1;min-width:150px;background:#e8f4f8;padding:15px;border-radius:8px;text-align:center;''><strong>Fieldbus</strong><p>Digital (Foundation, Profibus)</p></div></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>O sinal <strong>4-20 mA</strong> é o mais usado na indústria. 4mA = 0% e 20mA = 100%. Por que não começa em 0? Para detectar falha de cabo (0mA = fio rompido)!</p></div>' WHERE titulo = 'Resumo: Instrumentação';
